import fs from 'fs-extra';
import path from 'path';
import { logger } from '../utils/logger.js';
/**
 * Generates a Markdown performance report suitable for PR comments and wikis.
 */
export class MarkdownReporter {
    static async report(result, outputPath) {
        const finalPath = outputPath || path.join(result.project.rootPath, 'next-optimize-report.md');
        const md = this.generateMarkdown(result);
        try {
            await fs.writeFile(finalPath, md);
            logger.info(`Markdown report generated at: ${finalPath}`);
        }
        catch (error) {
            logger.error('Failed to generate Markdown report:', error);
        }
    }
    static generateMarkdown(result) {
        const date = new Date(result.timestamp).toLocaleString();
        const scoreLabel = result.score.overall >= 90 ? 'Excellent' :
            result.score.overall >= 70 ? 'Good' :
                result.score.overall >= 50 ? 'Needs Optimization' : 'Critical';
        let md = `# Next Optimize Report\n\n`;
        md += `> Generated on ${date}\n\n`;
        md += `## Overall Score: ${result.score.overall}/100 (${scoreLabel})\n\n`;
        md += `| Property | Value |\n|----------|-------|\n`;
        md += `| Framework | ${result.project.framework} ${result.project.version || ''} |\n`;
        md += `| Build Tool | ${result.project.buildTool} |\n`;
        md += `| Package Manager | ${result.project.packageManager} |\n`;
        md += `| Issues Found | ${result.issues.length} |\n\n`;
        md += `## Category Scores\n\n`;
        md += `| Category | Score |\n|----------|-------|\n`;
        for (const [cat, val] of Object.entries(result.score.categories)) {
            md += `| ${cat} | ${val} |\n`;
        }
        md += `\n`;
        if (result.recommendations.length > 0) {
            md += `## Top Recommendations\n\n`;
            result.recommendations.slice(0, 10).forEach((rec, i) => {
                md += `${i + 1}. **${rec.action}** — Impact: ${rec.impact}, Effort: ${rec.effort}\n`;
            });
            md += `\n`;
        }
        if (result.issues.length > 0) {
            md += `## Issues\n\n`;
            const grouped = this.groupBySeverity(result.issues);
            for (const [severity, issues] of Object.entries(grouped)) {
                md += `### ${severity.charAt(0).toUpperCase() + severity.slice(1)} (${issues.length})\n\n`;
                for (const issue of issues) {
                    md += `- **${issue.title}** [${issue.category}]\n`;
                    md += `  - ${issue.description}\n`;
                    if (issue.file)
                        md += `  - Location: \`${issue.file}${issue.line ? `:${issue.line}` : ''}\`\n`;
                    if (issue.suggestion)
                        md += `  - Fix: ${issue.suggestion}\n`;
                }
                md += `\n`;
            }
        }
        else {
            md += `## No Issues Detected\n\nYour project is in great shape!\n`;
        }
        md += `---\n*Generated by [Next Optimize](https://next-optimize.dev) CLI*\n`;
        return md;
    }
    static groupBySeverity(issues) {
        const order = ['critical', 'high', 'medium', 'low', 'info'];
        const grouped = {};
        for (const sev of order) {
            const filtered = issues.filter((i) => i.severity === sev);
            if (filtered.length > 0)
                grouped[sev] = filtered;
        }
        return grouped;
    }
}
